using System.Threading;

public class Cache
{
    private readonly object _gate = new object();

    public void Add()
    {
        Monitor.Enter(_gate);
        try
        {
            Mutate();
        }
        finally
        {
            Monitor.Exit(_gate);
        }
    }

    private void Mutate()
    {
    }
}
